// ============================================================
// src/pages/RequestCardPage.js
// Form to request a library card for a specific book
// Full validation — all fields required
// ============================================================
import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { DUMMY_BOOKS, saveCardRequest } from '../services/data';

const today = new Date().toISOString().split('T')[0];

const RequestCardPage = () => {
  const { currentUser } = useAuth();

  const [form, setForm] = useState({
    studentName: currentUser?.name || '',
    enrollmentNo: currentUser?.enrollmentNo || '',
    bookId: '',
    requestDate: today,
    returnDate: '',
    purpose: '',
  });
  const [errors,  setErrors]  = useState({});
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);

  // ── Handle change ────────────────────────────────────────
  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
    setErrors(prev => ({ ...prev, [name]: '' }));
    setSuccess('');
  };

  // ── Validation ───────────────────────────────────────────
  const validate = () => {
    const errs = {};
    if (!form.studentName.trim())  errs.studentName  = 'Student name is required.';
    if (!form.enrollmentNo.trim()) errs.enrollmentNo = 'Enrollment number is required.';
    if (!form.bookId)              errs.bookId       = 'Please select a book.';
    if (!form.requestDate)         errs.requestDate  = 'Request date is required.';
    if (!form.returnDate)          errs.returnDate   = 'Expected return date is required.';
    else if (form.returnDate <= form.requestDate)
      errs.returnDate = 'Return date must be after the request date.';
    if (!form.purpose.trim())      errs.purpose      = 'Purpose / reason is required.';
    else if (form.purpose.trim().length < 10)
      errs.purpose = 'Please provide at least 10 characters describing your purpose.';
    return errs;
  };

  // ── Submit ───────────────────────────────────────────────
  const handleSubmit = (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }

    setLoading(true);
    const selectedBook = DUMMY_BOOKS.find(b => b.id === parseInt(form.bookId));
    setTimeout(() => {
      saveCardRequest({
        studentName: form.studentName,
        bookTitle:   selectedBook?.title || '',
        requestDate: form.requestDate,
        returnDate:  form.returnDate,
        purpose:     form.purpose,
      });
      setSuccess(`✅ Card request submitted successfully for "${selectedBook?.title}". The librarian will review it shortly.`);
      setLoading(false);
      handleReset(true); // reset form but keep success
    }, 700);
  };

  // ── Reset ────────────────────────────────────────────────
  const handleReset = (keepSuccess = false) => {
    setForm({ studentName: currentUser?.name || '', enrollmentNo: currentUser?.enrollmentNo || '', bookId: '', requestDate: today, returnDate: '', purpose: '' });
    setErrors({});
    if (!keepSuccess) setSuccess('');
  };

  const selectedBook = DUMMY_BOOKS.find(b => b.id === parseInt(form.bookId));

  return (
    <div className="page-wrapper">
      <div className="container">
        <div className="row justify-content-center">
          <div className="col-lg-8">

            {/* Header */}
            <div className="mb-4">
              <h2 className="section-title">
                <i className="bi bi-credit-card me-2" style={{ color: 'var(--accent)' }}></i>
                Request Library Card
              </h2>
              <p className="section-subtitle">Fill in the form below to request a book borrowing card</p>
            </div>

            {/* Success alert */}
            {success && (
              <div className="alert alert-success lib-alert mb-4">
                <i className="bi bi-check-circle-fill me-2"></i>{success}
              </div>
            )}

            {/* Main form card */}
            <div className="lib-card">
              <div className="lib-card-header">
                <h5><i className="bi bi-file-earmark-text me-2"></i>Card Request Form</h5>
              </div>
              <div className="p-4">
                <form onSubmit={handleSubmit} noValidate>
                  <div className="row g-3">

                    {/* Student Name */}
                    <div className="col-md-6">
                      <label className="lib-label">Student Name *</label>
                      <input type="text" name="studentName" value={form.studentName} onChange={handleChange}
                        className={`form-control lib-form-control ${errors.studentName ? 'is-invalid' : ''}`}
                        placeholder="Full name" />
                      {errors.studentName && <div className="invalid-feedback">{errors.studentName}</div>}
                    </div>

                    {/* Enrollment Number */}
                    <div className="col-md-6">
                      <label className="lib-label">Enrollment Number *</label>
                      <input type="text" name="enrollmentNo" value={form.enrollmentNo} onChange={handleChange}
                        className={`form-control lib-form-control ${errors.enrollmentNo ? 'is-invalid' : ''}`}
                        placeholder="e.g. CS2021001" />
                      {errors.enrollmentNo && <div className="invalid-feedback">{errors.enrollmentNo}</div>}
                    </div>

                    {/* Book selection */}
                    <div className="col-12">
                      <label className="lib-label">Select Book *</label>
                      <select name="bookId" value={form.bookId} onChange={handleChange}
                        className={`form-select lib-form-control ${errors.bookId ? 'is-invalid' : ''}`}>
                        <option value="">— Choose a book —</option>
                        {DUMMY_BOOKS.map(b => (
                          <option key={b.id} value={b.id} disabled={b.available === 0}>
                            {b.title} — {b.author} {b.available === 0 ? '(Not Available)' : `(${b.available} available)`}
                          </option>
                        ))}
                      </select>
                      {errors.bookId && <div className="invalid-feedback">{errors.bookId}</div>}
                    </div>

                    {/* Book details preview */}
                    {selectedBook && (
                      <div className="col-12">
                        <div className="p-3" style={{ background: 'rgba(233,69,96,.05)', border: '1.5px solid rgba(233,69,96,.2)', borderRadius: 'var(--radius-sm)' }}>
                          <div className="row g-2" style={{ fontSize: '.83rem' }}>
                            <div className="col-md-6">
                              <span style={{ color: 'var(--text-muted)' }}>Author: </span>
                              <strong>{selectedBook.author}</strong>
                            </div>
                            <div className="col-md-6">
                              <span style={{ color: 'var(--text-muted)' }}>Category: </span>
                              <strong>{selectedBook.category}</strong>
                            </div>
                            <div className="col-md-6">
                              <span style={{ color: 'var(--text-muted)' }}>ISBN: </span>
                              <strong>{selectedBook.isbn}</strong>
                            </div>
                            <div className="col-md-6">
                              <span style={{ color: 'var(--text-muted)' }}>Available copies: </span>
                              <strong style={{ color: '#059669' }}>{selectedBook.available}</strong>
                            </div>
                          </div>
                        </div>
                      </div>
                    )}

                    {/* Request Date */}
                    <div className="col-md-6">
                      <label className="lib-label">Request Date *</label>
                      <input type="date" name="requestDate" value={form.requestDate} onChange={handleChange}
                        className={`form-control lib-form-control ${errors.requestDate ? 'is-invalid' : ''}`}
                        min={today} />
                      {errors.requestDate && <div className="invalid-feedback">{errors.requestDate}</div>}
                    </div>

                    {/* Return Date */}
                    <div className="col-md-6">
                      <label className="lib-label">Expected Return Date *</label>
                      <input type="date" name="returnDate" value={form.returnDate} onChange={handleChange}
                        className={`form-control lib-form-control ${errors.returnDate ? 'is-invalid' : ''}`}
                        min={today} />
                      {errors.returnDate && <div className="invalid-feedback">{errors.returnDate}</div>}
                    </div>

                    {/* Purpose */}
                    <div className="col-12">
                      <label className="lib-label">Purpose / Reason *</label>
                      <textarea name="purpose" value={form.purpose} onChange={handleChange} rows={3}
                        className={`form-control lib-form-control ${errors.purpose ? 'is-invalid' : ''}`}
                        placeholder="Briefly describe why you need this book (min. 10 characters)…" />
                      <div className="d-flex justify-content-between mt-1">
                        {errors.purpose ? (
                          <div className="invalid-feedback d-block">{errors.purpose}</div>
                        ) : <span></span>}
                        <span style={{ fontSize: '.75rem', color: 'var(--text-muted)' }}>{form.purpose.length} chars</span>
                      </div>
                    </div>

                    {/* Buttons */}
                    <div className="col-12 d-flex gap-2 flex-wrap mt-2">
                      <button type="submit" className="btn btn-lib-primary" disabled={loading}>
                        {loading
                          ? <><span className="spinner-border spinner-border-sm me-2"></span>Submitting…</>
                          : <><i className="bi bi-send me-2"></i>Submit Request</>}
                      </button>
                      <button type="button" className="btn btn-lib-secondary" onClick={() => handleReset()}>
                        <i className="bi bi-arrow-counterclockwise me-2"></i>Reset Form
                      </button>
                    </div>
                  </div>
                </form>
              </div>
            </div>

            {/* Info notice */}
            <div className="alert lib-alert alert-info mt-3" style={{ background: 'rgba(99,102,241,.08)', border: '1px solid rgba(99,102,241,.2)', color: '#4338ca' }}>
              <i className="bi bi-info-circle me-2"></i>
              <strong>Note:</strong> After submission, your request will be reviewed by the librarian. Cards are issued within 1–2 working days. Late return incurs a fine of ₹5/day.
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default RequestCardPage;
